function ModelBackflow:OnModelInit()
    self:InitData()
    self:ModelNetMsgRecv(LProtoIds.RegressionInfoResp,function(...) self:OnRegressionInfoResp(...) end)
    -- self:ModelNetMsgRecv(LProtoIds.RegressionLoginAwardResp,function(...) self:OnRegressionLoginAwardResp(...) end)
    self:ModelNetMsgRecv(LProtoIds.RegressionPrivilegeResp,function(...) self:OnRegressionPrivilegeResp(...) end)
