function ModelBackflow:InitData()
    local _taskByQuestList = {}
    for i, v in pairs(GameTable.ReturnBackActiveTaskRef) do
        _taskByQuestList[v.quest] = v
    end
    self._taskByQuestList = _taskByQuestList
end
