-- Msg Begin
--回归相关数据，登陆收到该协议，说明活动开启
function ModelBackflow:OnRegressionInfoResp(pb)
    local _endTime = pb.endTime or 0
    local rewardAddition = pb.rewardAddition or 100
    local shopEndTime = pb.shopEndTime
    self._endTime = _endTime
    self._rewardAddition = rewardAddition
    self._shopEndTime = shopEndTime
    if tonumber(_endTime) <= 0 or GetTimestamp() > tonumber(pb.endTime)/1000 then
        GF.CloseWndByName("UIBackin")
        return
    end
    self:RegressionPrivilegeReq()
end
--请求登陆奖励信息
function ModelBackflow:RegressionLoginAwardReq(day)
    local pb = LProtoHelper.CreateProto(LProtoIds.RegressionLoginAwardReq)
    pb.day = day or 0                       --day == 0：请求所有登陆奖励信息；day > 0:领取固定和挂机奖励
    SendMessage(pb,LProtoIds.RegressionLoginAwardReq)
end
function ModelBackflow:OnRegressionLoginAwardResp(pb)
    local day = pb.day                      --请求所有登陆奖励信息；refId>0:领取指定天的奖励
    local awardInfo = pb.awardInfo          --登陆奖励信息
    local list = self._awardInfo or {}
    if day <= 0 then
        list = {}
    end
    for i, v in ipairs(awardInfo) do
        local info = StructRegressionLoginAward:New()
        info:CreateByPb(v)
        list[info.day] = info
    end
    self._awardInfo = list
end
--获得特权信息
function ModelBackflow:RegressionPrivilegeReq()
    local pb = LProtoHelper.CreateProto(LProtoIds.RegressionPrivilegeReq)
    SendMessage(pb,LProtoIds.RegressionPrivilegeReq)
end
function ModelBackflow:OnRegressionPrivilegeResp(pb)
    local refIds = pb.refId
    local list = {}
    for i, v in ipairs(refIds) do
        local ref = gModelBackflow:GetRegressionPrivilegesShowRefByRefId(v)
        if not ref then
            printErrorN("ModelBackflow nil ref RegressionPrivilegesRef :"..v)
        else
            local type = ref.Type
            local _list = list[type] or {}
            table.insert(_list,ref)
            list[type] = _list
        end
    end
    self._privilegesTypeList = list
end
--获得直购礼包信息
function ModelBackflow:RegressionGiftReq(type,refId,selected)
    local pb = LProtoHelper.CreateProto(LProtoIds.RegressionGiftReq)
    pb.type = type                                  --type == 1请求所有礼包信息;type == 2保存;type == 3购买;
    pb.refId = refId or 0                           --直购礼包refId ==0时请求所有礼包信息，>0时：选定某个礼包固定奖励
    if selected then
        pb.selected = selected                      --选择奖励 ","分割
    end
    SendMessage(pb,LProtoIds.RegressionGiftReq)
end
function ModelBackflow:OnRegressionGiftResp(pb)
    local type = pb.type                            --type == 1请求所有礼包信息;type == 2保存;type == 3购买;
    local refId = pb.refId                          --直购礼包refId ==0时请求所有礼包信息，>0时：选定某个礼包固定奖励
    local giftList = pb.giftList                    --可购买礼包列表
    local list = self._giftList or {}
    if type == 1 then
        list = {}
    end
    for i, v in ipairs(giftList) do
        local info = StructRegressionGift:New()
        info:CreateByPb(v)
        list[info.refId] = info
    end
    self._giftList = list
end
function ModelBackflow:RegressionMonsterReq()
    local pb = LProtoHelper.CreateProto(LProtoIds.RegressionMonsterReq)
    SendMessage(pb,LProtoIds.RegressionMonsterReq)
end
function ModelBackflow:OnRegressionMonsterResp(pb)
    local refIds = pb.refId
    local endTime = pb.endTime
    local list = {}
    for i, v in ipairs(refIds) do
        local info = StructRegressionMonster:New()
        info:CreateByPb(v)
        table.insert(list,info)
    end
    self._monsterInfos = list
    self._monsterEndTime = endTime
end
