-- Get pb
--活动剩余时间
function ModelBackflow:GetResidueTime()
    local _endTime = self._endTime or 0
    local time = tonumber(_endTime)/1000 - GetTimestamp()
    return time
end
function ModelBackflow:GetRewardAddition()
    local _rewardAddition = self._rewardAddition
    return _rewardAddition and _rewardAddition/100 or 1
end
function ModelBackflow:GetShopEndTime()
    local _shopEndTime = self._shopEndTime
    return _shopEndTime and tonumber(_shopEndTime)/1000 or 0
end
--登录奖励信息
function ModelBackflow:GetAwardInfos()
    local list = {}
    for i, v in pairs(self._awardInfo) do
        table.insert(list,v)
    end
    return list
end
function ModelBackflow:GetPrivilegesTypeList()
    local list = self._privilegesTypeList or {}
    local _list = {}
    for i, v in pairs(list) do
        table.insert(_list,{type = i,showList = v})
    end
    return _list
end
function ModelBackflow:GetPrivilegesTypeListByType(type)
    local list = self._privilegesTypeList or {}
    return list[type]
end
--超值特惠礼包列表
function ModelBackflow:GetGiftList()
    return self._giftList
end
--当天重返火线boss列表
function ModelBackflow:GetMonsterInfo()
    return self._monsterInfos or {} ,self._monsterEndTime or 0
end
-- Get config
function ModelBackflow:RegressionConfigRefByKey(key)
    return GameTable.ReturnBackConfigRef[key]
end
function ModelBackflow:RegressionBackflowRefByRefId(refId)
    return GameTable.ReturnBackBackflowRef[refId]
end
function ModelBackflow:RegressionBackflowRef()
    local list = {}
    for i, v in pairs(GameTable.ReturnBackBackflowRef) do
        table.insert(list,v)
    end
    table.sort(list,function (a,b)
        return a.refId < b.refId
    end)
    return list
end
function ModelBackflow:RegressionFixedRewardRefByRefId(refId)
    return GameTable.ReturnBackFixedRewardRef[refId]
end
function ModelBackflow:RegressionOnhookRewardRefByRefId(refId)
    return GameTable.RegressionOnhookRewardRef[refId]
end
function ModelBackflow:GetRegressionPrivilegesRefByRefId(refId)
    return GameTable.RegressionPrivilegesRef[refId]
end
function ModelBackflow:GetRegressionPrivilegesShowRefByRefId(refId)
    return GameTable.ReturnBackPrivilegesShowRef[refId]
end
function ModelBackflow:RegressionPrivilegesShowRefByType(type)
    for i, v in pairs(GameTable.ReturnBackPrivilegesShowRef) do
        if v.Type == type then
            return v
        end
    end
    return nil
end
function ModelBackflow:RegressionActiveTaskRefByQuest(quest)
    local ref = self._taskByQuestList[quest]
    if not ref then
        return false
    end
    local functionOpen = ref.functionOpen
    if functionOpen <= 0 then
        return true
    end
    local bool = gModelFunctionOpen:CheckIsOpened(functionOpen,false)
    return bool
end
function ModelBackflow:RegressionPreferentialRefByRefId(refId)
    return GameTable.ReturnBackPreferentialRef[refId]
end
function ModelBackflow:RegressionChallengeRefByRefId(refId)
    return GameTable.ReturnBackChallengeRef[refId]
end
function ModelBackflow:RegressionChallengeRef()
    local list = {}
    for i, v in pairs(GameTable.ReturnBackChallengeRef) do
        table.insert(list,v)
    end
    table.sort(list,function (a,b)
        return a.refId < b.refId
    end)
    return list
end
