function ModelBackflow:GetBackShopIsOpent()
    local _shopEndTime = self:GetShopEndTime()
    local endTime = _shopEndTime
    if endTime <= 0 then
        return false
    end
    local time = GetTimestamp()
    local timespan = endTime - time
    if timespan <= 0 then
        return false
    end
    return true
end
-- Func End

function ModelBackflow:IsActivityOpen()
    return self:GetResidueTime() > 0
end
